local SceneType = {
    AdvancedScene = 1, ---进阶类型场景
}

local Scenes = {
    [SceneType.AdvancedScene] = {}
}

SceneManager = {}

---根据进阶ID获取进阶场景
function SceneManager:getAdvancedScene(advancedId)
    return Scenes[SceneType.AdvancedScene][tostring(advancedId)]
end

---添加一个进阶场景
function SceneManager:addAdvancedScene(scene)
    Scenes[SceneType.AdvancedScene][tostring(scene.Id)] = scene
end

---删除一个进阶场景
function SceneManager:removeAdvancedScene(scene)
    Scenes[SceneType.AdvancedScene][tostring(scene.Id)] = nil
end

---加入到进阶场景，等待或开始进阶
function SceneManager:joinAdvancedScene(player, advancedId)
    local scene = self:getAdvancedScene(advancedId)
    if not scene then
        scene = AdvancedScene.new(advancedId)
        if not scene:isInit() then
            return
        end
        self:addAdvancedScene(scene)
    end
    scene:addPlayer(player)
end

function SceneManager:onTick()
    for _, scenes in pairs(Scenes) do
        for _, scene in pairs(scenes) do
            scene:onTick()
        end
    end
end

function SceneManager:onPlayerLogout(player)
    for _, scenes in pairs(Scenes) do
        for _, scene in pairs(scenes) do
            scene:removePlayer(player)
        end
    end
end